const input = $input.first().json;
const body = input.body || input;

const sheetId = body.sheetId;
if (!sheetId) return [];

const instagramUrls = (body.instagram || []).filter(Boolean);
const facebookUrls = (body.facebook || []).filter(Boolean);
const tiktokUrls = (body.tiktok || []).filter(Boolean);

if (instagramUrls.length === 0) throw new Error('Se requiere al menos una URL de Instagram.');

// Extraer handle de una URL para detección de marca
function extractHandle(url) {
  return (url.replace(/https?:\/\/(www\.)?/, '').split('/').filter(p => p && p !== '@')[1] || '').toLowerCase();
}

// brands: handles de instagram como referencia para detectar a qué marca pertenece cada post
const brands = instagramUrls.map(extractHandle);

// TikTok: extraer @handle de la URL
const tiktokProfiles = tiktokUrls.map(url => {
  const m = url.match(/@([\w.]+)/);
  return m ? '@' + m[1] : url;
});

const clientEmail = body.clientEmail || '';
const myBrand = body.myBrand || brands[0];
const followers = body.followers || {};
const plan = body.plan || 'pro';
const days = body.days || 90;
const resultsLimit = body.resultsLimit || 30;
const fromDate = body.fromDate || new Date(Date.now() - days * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

return [{ brands, sheetId, clientEmail, myBrand, followers, plan, fromDate, resultsLimit, instagramUrls, facebookUrls, tiktokProfiles }];

const items = $input.all();
const existingUrls = items
  .map(i => (i.json.POSTEO || '').trim())
  .filter(Boolean)
  .join(',');
return [{ existingUrls }];

return $input.all().map(item => {
  const d = item.json;
  const url = d.url || (d.shortCode ? 'https://www.instagram.com/p/' + d.shortCode + '/' : '');
  return {
    url,
    caption: d.caption || d.alt || '',
    hashtags: Array.isArray(d.hashtags) ? d.hashtags : [],
    timestamp: d.timestamp || d.takenAtTimestamp || '',
    likesCount: d.likesCount || d.likes || 0,
    commentsCount: d.commentsCount || d.comments || 0,
    type: d.type || 'image',
    ownerUsername: d.ownerUsername || d.username || '',
    ownerFollowerCount: d.ownerFollowerCount || d.followersCount || 0,
    videoViewCount: d.videoViewCount || d.videoPlayCount || 0,
    isSponsored: !!(d.isSponsored || d.isPinned),
    platform: 'INSTAGRAM'
  };
});

return $input.all().map(item => {
  const d = item.json;
  const text = d.text || d.message || d.story || '';
  const hashtags = (text.match(/#[\w\u00C0-\u024F]+/g) || []).map(h => h.slice(1));
  return {
    url: d.url || d.postUrl || d.link || '',
    caption: text,
    hashtags,
    timestamp: d.time || d.createdTime || d.date || '',
    likesCount: d.likes || d.likesCount || d.reactionsCount || 0,
    commentsCount: d.comments || d.commentsCount || 0,
    type: d.type || 'photo',
    ownerUsername: d.pageName || d.pageAlias || d.username || '',
    videoViewCount: d.videoViewCount || d.views || 0,
    ownerFollowerCount: d.pageFans || d.fans || d.followers || d.pageFollowers || 0,
    isSponsored: !!(d.isSponsored),
    platform: 'FACEBOOK'
  };
});

return $input.all().map(item => {
  const d = item.json;
  const text = d.text || d.desc || '';
  const hashtags = Array.isArray(d.hashtags)
    ? d.hashtags.map(h => h.name || h.title || h).filter(h => typeof h === 'string')
    : (text.match(/#[\w\u00C0-\u024F]+/g) || []).map(h => h.slice(1));
  return {
    url: d.webVideoUrl || d.videoUrl || d.shareUrl || '',
    caption: text,
    hashtags,
    timestamp: d.createTimeISO || (d.createTime ? new Date(d.createTime * 1000).toISOString() : ''),
    likesCount: d.diggCount || d.likeCount || 0,
    commentsCount: d.commentCount || 0,
    type: 'video',
    ownerUsername: (d.authorMeta && d.authorMeta.name) || d.authorUniqueId || '',
    videoViewCount: d.playCount || d.viewCount || 0,
    isSponsored: false,
    platform: 'TIKTOK'
  };
});

try {
  const raw = $input.first().json;
  const originalPosts = $('Aggregate Posts').first().json.posts || [];
  const config = $('Set Config').first().json;
  const marcas = config.brands.map(b => b.toLowerCase());
  const fromDate = config.fromDate || '2000-01-01';
  const followersMap = (() => { try { return $('Extract Follower Counts').first().json.followersMap || {}; } catch(e) { return {}; } })();

  let analysisArray;
  if (raw.choices && raw.choices[0]) {
    const content = raw.choices[0].message?.content || '';
    const parsed = JSON.parse(content);
    analysisArray = parsed.analysis || parsed;
  } else if (Array.isArray(raw)) {
    analysisArray = raw;
  } else {
    throw new Error('Formato inesperado: ' + JSON.stringify(Object.keys(raw)));
  }

  if (!Array.isArray(analysisArray)) throw new Error('analysis no es un array');

  const analysisMap = {};
  for (const a of analysisArray) {
    if (a.url) analysisMap[a.url] = a;
  }

  const results = [];
  for (const post of originalPosts) {
    try {
      const url = post.url || '';
      const analysis = analysisMap[url];
      if (!analysis) continue;

      const fecha = post.timestamp ? new Date(post.timestamp).toISOString().slice(0, 10) : '2000-01-01';
      if (fecha < fromDate) continue;

      const owner = (post.ownerUsername || post.username || '').toLowerCase();
      const marcaFinal = marcas.find(m => owner.includes(m) || m.includes(owner));
      if (!marcaFinal) continue;

      const likes = post.likesCount || 0;
      const comments = post.commentsCount || 0;
      const seguidores = followersMap[marcaFinal] || config.followers?.[marcaFinal] || post.ownerFollowerCount || post.followersCount || 0;
      const eng = seguidores > 0 ? (((likes + comments) / seguidores) * 100).toFixed(2) + '%' : '0%';

      const t = (post.type || '').toLowerCase();
      const contentType = post.platform === 'TIKTOK' ? 'VIDEO'
        : t.includes('video') || t.includes('reel') ? 'VIDEO'
        : t.includes('sidecar') || t.includes('album') ? 'SIDECAR' : 'IMAGE';

      const isSponsored = !!(post.isSponsored || post.isPinned);

      results.push({
        marca: marcaFinal,
        pilar: ['Branding','Producto','Promo','Influencer','Educacional'].includes(analysis.pilar) ? analysis.pilar : 'Branding',
        fecha,
        distribucion: isSponsored ? 'PAUTA' : 'ORGÁNICO',
        positivo: analysis.sentimiento?.positivo || 0,
        negativo: analysis.sentimiento?.negativo || 0,
        neutro: analysis.sentimiento?.neutro || 0,
        likes,
        comments,
        engagement: eng,
        insight: analysis.insight || 'Sin análisis',
        url,
        videoViews: post.videoViewCount || post.videoPlayCount || 0,
        contentType,
        isSponsored,
        hashtags: Array.isArray(post.hashtags) ? post.hashtags.join(',') : '',
        platform: post.platform || 'INSTAGRAM',
        followers: seguidores
      });
    } catch (e) { /* skip */ }
  }

  return results;
} catch (e) {
  return [];
}

const config = $('Set Config').first().json;
const clientEmail = config.clientEmail || '';
if (!clientEmail) return [];

const plan = config.plan || 'pro';
const dashboardUrl = 'https://www.tombaio.com/Instagram_Intelligence%20(24).html?id='
  + config.sheetId + '&myBrand=' + encodeURIComponent(config.myBrand) + '&plan=' + plan;
const allPosts = $input.first().json.data || [];
const postCount = allPosts.length;

const emailBody = '<!DOCTYPE html><html><body style="font-family:-apple-system,BlinkMacSystemFont,\'Segoe UI\',sans-serif;background:#f7f7f8;margin:0;padding:40px 20px">'
  + '<div style="max-width:560px;margin:0 auto;background:#fff;border-radius:16px;overflow:hidden;border:1px solid #e0e0e5">'
  + '<div style="background:#111112;padding:28px 36px"><div style="font-size:1.2rem;font-weight:700;color:#fff">tomb<span style="color:#0057ff">ai</span>o</div></div>'
  + '<div style="padding:40px 36px">'
  + '<h1 style="font-size:1.5rem;color:#111112;margin:0 0 16px">Tu Dashboard Pro está listo 🎯</h1>'
  + '<p style="color:#6b6b75;line-height:1.7;margin:0 0 8px">Analizamos <strong>' + postCount + ' posts</strong> de Instagram, Facebook y TikTok.</p>'
  + '<p style="color:#6b6b75;line-height:1.7;margin:0 0 24px">Encontrás todos los insights en tu dashboard:</p>'
  + '<a href="' + dashboardUrl + '" style="display:inline-block;background:#0057ff;color:#fff;text-decoration:none;font-weight:600;padding:14px 32px;border-radius:8px;font-size:1rem">Ver mi Dashboard →</a>'
  + '<p style="color:#9f9fa8;font-size:.85rem;margin:28px 0 0;line-height:1.6">¿Dudas? Escribinos a <a href="mailto:hola@tombaio.com" style="color:#0057ff">hola@tombaio.com</a></p>'
  + '</div>'
  + '<div style="background:#f7f7f8;padding:20px 36px;border-top:1px solid #e0e0e5"><p style="color:#9f9fa8;font-size:.75rem;margin:0">tombaio · Inteligencia competitiva · <a href="https://www.tombaio.com" style="color:#9f9fa8">tombaio.com</a></p></div>'
  + '</div></body></html>';

return [{ clientEmail, dashboardUrl, postCount, plan, emailBody }];

const followersMap = {};
const config = $('Set Config').first().json;
const marcas = config.brands.map(b => b.toLowerCase());

const deepScan = (obj) => {
  if (!obj || typeof obj !== 'object') return 0;
  const known = ['followersCount','follower_count','ownerFollowersCount','ownerFollowerCount','fans','followers'];
  for (const f of known) { if (obj[f] > 0) return obj[f]; }
  if (obj.edge_followed_by?.count > 0) return obj.edge_followed_by.count;
  for (const k of Object.keys(obj)) {
    const kl = k.toLowerCase();
    if ((kl.includes('follower') || kl === 'fans') && !kl.includes('following') && typeof obj[k] === 'number' && obj[k] > 0) return obj[k];
  }
  return 0;
};

const matchMarca = (u) => {
  const uu = (u || '').toLowerCase();
  return marcas.find(m => m === uu || (m.length >= 5 && uu.startsWith(m)) || (uu.length >= 5 && m.startsWith(uu)));
};

// Instagram
try {
  const profiles = [];
  for (const item of $('Get Follower Counts').all()) {
    const d = item.json;
    if (Array.isArray(d)) { profiles.push(...d); }
    else if (Array.isArray(d.body)) { profiles.push(...d.body); }
    else { profiles.push(d); }
  }
  for (const d of profiles) {
    const marca = matchMarca(d.username || d.ownerUsername || d.handle || '');
    if (!marca || followersMap[marca] > 0) continue;
    const f = deepScan(d) || deepScan(d.owner) || deepScan(d.user) || 0;
    if (f > 0) followersMap[marca] = f;
  }
} catch(e) {}

// TikTok
try {
  for (const item of $('Get TT Followers').all()) {
    const d = item.json;
    const marca = matchMarca(d.authorMeta?.name || d.authorUniqueId || '');
    if (!marca || followersMap[marca] > 0) continue;
    const f = d.authorMeta?.fans || d.authorStats?.followerCount || deepScan(d.authorMeta) || 0;
    if (f > 0) followersMap[marca] = f;
  }
} catch(e) {}

return [{ followersMap }];
